#!/usr/bin/env python3
"""
mkt-original commentary -- Hosea chapters 1-6 (84 verses)
Run: python3 scripts/zc-original-hosea-1-6-full.py

Hosea prophesied in the northern kingdom of Israel ca. 755-725 BCE,
the final decades before Assyria destroyed Samaria (722 BCE). His
marriage to Gomer is the enacted parable of YHWH's covenant with Israel.

Key Hebrew terms throughout:
  zonah (H2181) -- to be a prostitute/unfaithful; the dominant metaphor
  hesed (H2617) -- covenant love/loyalty; the governing divine attribute
  daath Elohim (H1847+H430) -- knowledge of God; the covenant intimacy Israel abandoned
  lo-ammi (not my people) / lo-ruhamah (not loved) -- covenant reversal
  ruah zenutim (H7307+H2183) -- spirit of prostitution; ch 4-5 pathology
  aras (H781) -- to betroth; the triple betrothal formula of 2:19-20
  shub (H7725) -- to return/repent; the call of ch 6
  Ephraim -- the leading tribe of the northern kingdom; Hosea's frequent address
  ba'al/ba'alim (H1167/H1168) -- lord/master and the Canaanite deity/ies
  ishi (H376) -- my husband; vs ba'ali (my lord/master) in 2:16
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HOSEA = {
    "1": {
        "1": "<p><strong>Devar-YHWH asher hayah el-Hoshea ben-Beeri</strong> -- 'The word of YHWH that came to Hosea son of Beeri.' The superscription anchors the book in both prophetic authority (<em>devar-YHWH</em>, the word of YHWH) and historical precision: the reigns listed span ca. 793-715 BCE in the south (Uzziah, Jotham, Ahaz, Hezekiah) and ca. 793-753 BCE in the north (Jeroboam II). Hosea's ministry in the northern kingdom is the sole book of the Latter Prophets whose primary audience is Israel (not Judah). <em>Hoshea</em> (H1954) means 'salvation' -- the same root as Joshua and Jesus (<em>Yeshua</em>). The name of the prophet whose message is overwhelmingly one of judgment carries the embedded promise that judgment is not YHWH's final word.</p>",
        "2": "<p><strong>Techillat dibber-YHWH be-Hoshea</strong> -- 'When the LORD first spoke through Hosea.' The opening of Hosea's prophetic career is immediately scandalous. <em>Lekh qach-lekha eshet zenutim</em> -- 'Go, take for yourself a wife of unfaithfulness.' <em>Zenutim</em> (H2183, fornication/prostitution/unfaithfulness) is the key term: whether this refers to a woman who was already a prostitute or to one who would become unfaithful is debated in the tradition. The MKT reads 'a wife of unfaithfulness' as describing her character rather than her profession. <em>Ki-zanoh tizhneh ha-aretz me-acharei YHWH</em> -- 'for the land commits great fornication by departing from YHWH.' The marriage is enacted prophecy: Hosea's domestic experience maps onto YHWH's covenant grief. The verb <em>zanah</em> (to play the whore) is applied to Israel's relationship with YHWH -- the covenant as marriage, apostasy as adultery.</p>",
        "3": "<p><strong>Va-yelekh va-yiqach et-Gomer bat-Divlaim</strong> -- 'So he went and married Gomer daughter of Diblaim.' Hosea's obedience is immediate and unqualified. <em>Gomer</em> (H1586) -- a name from the Table of Nations (Gen 10:2-3) suggesting a northern or foreign association. <em>Divlaim</em> (H1691) -- 'double fig-cake'; the name has been taken as symbolic (sweetness leading to unfaithfulness) by some commentators, but it is more likely a personal name. <em>Va-tahar va-teled lo ben</em> -- 'and she conceived and bore him a son.' The birth narrative is terse and businesslike -- the focus is on the name and its meaning rather than the child himself. The pattern of the three children (son-daughter-son) with their symbolic names structures the rest of ch 1.</p>",
        "4": "<p><strong>Vayomer YHWH elav qera shemo Yizreel</strong> -- 'And the LORD said to him, Name him Jezreel.' <em>Yizreel</em> (H3157, 'God sows') is simultaneously a place name (the great valley where Jehu massacred the house of Ahab, 2 Kgs 9-10) and a word containing the promise of restoration ('God sows' = God will scatter and then re-sow his people). <em>Ki-od meat ufaqadti et-demei Yizreel al-beit Yehu</em> -- 'for in a little while I will punish the house of Jehu for the blood of Jezreel.' The very act that was approved in 2 Kings (Jehu's coup) is now declared a blood-guilt: either YHWH's assessment changed with the generations, or the approved act was nevertheless violent beyond what was required. <em>Ve-hishbatti mamlekhet beit-Yisrael</em> -- 'and I will bring the kingdom of the house of Israel to an end.' The northern dynasty's end (722 BCE) is prophesied.</p>",
        "5": "<p><strong>Ve-hayah ba-yom ha-hu</strong> -- 'On that day.' The prophetic formula of eschatological reversal introduces the judgment. <em>Ve-shabarti et-qeshet Yisrael be-emeq Yizreel</em> -- 'I will break the bow of Israel in the valley of Jezreel.' The <em>qeshet</em> (bow) was Israel's primary military weapon; its breaking in the valley of Jezreel -- where Jehu's dynasty began -- announces both military defeat and dynastic termination. The bow's breaking appears again in 2:18 as a peace promise: the bow will be removed from the land when covenant is restored. What is here a judgment will there be a gift.</p>",
        "6": "<p><strong>Va-tahar od va-teled bat</strong> -- 'She conceived again and bore a daughter.' The second child is female, marking a shift in the symbolic structure. <em>Vayomer lo qeri shemah Lo-Ruhamah</em> -- 'And God said to him, Name her Lo-ruhamah -- Not Pitied/Not Loved.' <em>Ruhamah</em> from <em>racham</em> (H7355, to have compassion/show mercy) -- the same root as <em>rechem</em> (womb) and <em>rachamim</em> (compassion/mercy). The name denies the foundational maternal compassion: YHWH will no longer show the compassion of a parent for a child. <em>Ki lo osif od arachem et-beit Yisrael</em> -- 'for I will no longer have mercy on the house of Israel.' The <em>od</em> (again/any more) marks the rupture: what was Israel's covenant possession (divine mercy) is being withdrawn. But the name's reversal in 2:23 ('I will have mercy on Lo-ruhamah') is the book's promise.</p>",
        "7": "<p><strong>Ve-et-beit Yehudah arachem</strong> -- 'But I will have mercy on the house of Judah.' The contrast between Israel (north, Lo-ruhamah) and Judah (south, still under mercy) is a recurring structural feature. <em>Ve-hoshati otam ba-YHWH Eloheihem</em> -- 'and I will save them by the LORD their God.' The divine name is emphatic -- YHWH himself as Savior, not any military power. <em>Ve-lo ohoshiam be-qeshet u-ve-cherev u-ve-milchamah be-susim u-ve-farashim</em> -- 'I will not save them by bow or sword or warfare, by horses or horsemen.' The salvation of Judah (presumably the deliverance from Sennacherib in 701 BCE is in view) will be miraculous, not military -- echoing the Exodus pattern. The contrast foreshadows 2:18's covenant of peace.</p>",
        "8": "<p><strong>Va-tigmol et-Lo-Ruhamah va-tahar va-teled ben</strong> -- 'After she weaned Lo-ruhamah, she conceived again and bore a son.' The verb <em>gamal</em> (to wean) marks the passage of time -- weaning in antiquity typically occurred around age two to three. Three children over approximately five to seven years. The third child receives the most devastating name. The pattern of Gomer's pregnancies mirrors Israel's progressive alienation from YHWH across the generations.</p>",
        "9": "<p><strong>Va-yomer qera shemo Lo-Ammi</strong> -- 'And God said, Name him Lo-ammi -- Not My People.' <em>Ammi</em> (H5971, my people) -- the covenant-formula term. 'My people / your God' is the compact bilateral covenant declaration (cf. Lev 26:12; Jer 7:23; 11:4; 30:22; Ezek 36:28). Its negation here is catastrophic: YHWH formally dissolves the covenant in its most essential formulation. <em>Ki atem lo-ammi ve-anokhi lo-ehyeh lakhem</em> -- 'for you are not my people, and I am not your God.' The phrase <em>lo-ehyeh</em> (I am not) is the negation of <em>ehyeh</em> (I AM) -- YHWH's own name from Exod 3:14. The covenant God who identified himself as 'I AM' now declares 'I am not' to his people. This is the nadir of the covenant, making the reversal in 2:23 and its NT fulfillment (Rom 9:25-26; 1 Pet 2:10) all the more powerful.</p>",
        "10": "<p><strong>Ve-hayah mispar benei-Yisrael ke-chol ha-yam</strong> -- 'Yet the number of the children of Israel will be like the sand of the sea.' Immediately after the covenant dissolution of v.9, the promise breaks through -- a structural feature of Hosea throughout. <em>Ke-chol ha-yam</em> (like the sand of the sea) -- the Abrahamic promise of innumerable descendants (Gen 22:17; 32:12). Despite Lo-ammi, the Abrahamic promise remains. <em>Asher lo-yimmad ve-lo yissafer</em> -- 'which cannot be measured or numbered.' <em>Ve-hayah bi-mekom asher-yiamer lahem lo-ammi atem yiamer lahem benei El-Chai</em> -- 'and in the place where it was said to them, You are not my people, there it shall be said to them, Sons of the living God.' The reversal: the place of rejection becomes the place of adoption. Paul quotes this verse in Rom 9:26 for the inclusion of Gentiles -- the 'not my people' becoming 'sons of the living God.' <em>El Chai</em> (the living God) contrasts with the dead idols Israel pursued.</p>",
        "11": "<p><strong>Ve-niqvetzu benei Yehudah u-venei Yisrael yachdav</strong> -- 'The children of Judah and Israel will be gathered together.' The eschatological reunion of the divided kingdoms -- a promise that runs throughout the prophets (Isa 11:12-13; Jer 31:1; Ezek 37:15-28). <em>Ve-samu lahem rosh echad</em> -- 'and they will appoint for themselves one head.' <em>Rosh echad</em> (one head) -- the messianic ruler who will unite the two kingdoms under one shepherd-king. <em>Ve-alu min-ha-aretz</em> -- 'and they will go up from the land.' The going-up suggests a new Exodus -- the dispersed gathered from the nations and returning to the land. <em>Ki gadol yom Yizreel</em> -- 'for great is the day of Jezreel.' The name Jezreel ('God sows') is now revalued: after the judgment of scattering, God re-sows his people in the land. The three children's names -- Lo-ammi, Lo-ruhamah, Jezreel -- are all reversed in the restoration promise.</p>"
    },
    "2": {
        "1": "<p><strong>Imru le-acheikhem Ammi</strong> -- 'Say to your brothers, My people.' Ch 2 opens with the reversal of the children's names: Lo-ammi becomes Ammi, Lo-ruhamah becomes Ruhamah. <em>Ve-la-achotekhem Ruhamah</em> -- 'and to your sisters, My beloved/pitied.' This is the answer to 1:6, 9: the 'not loved' is now addressed as 'loved.' The community's task is to speak these reversed names -- to declare the covenant restoration before it has fully arrived. The NT appropriation (1 Pet 2:9-10) addresses the church with the Hosea restoration language: 'Once you were not a people, but now you are God's people; once you had not received mercy, but now you have received mercy.'</p>",
        "2": "<p><strong>Rivu ve-imeikhem rivu</strong> -- 'Contend with your mother, contend.' The legal language of <em>riv</em> (H7378, to contend/bring a case/plead) opens a covenant lawsuit. The legal setting is a formal accusation: YHWH is the aggrieved party, Israel (the mother) is the defendant, and her children (the individual Israelites) are the witnesses and litigants. <em>Ki hi lo-ishti ve-anokhi lo-ishah</em> -- 'for she is not my wife, and I am not her husband.' The formal pronouncement of divorce in ancient Near Eastern law. The covenant marriage is dissolved by formal declaration -- the legal obverse of the covenant formula. <em>Ve-tasir zenutehah mi-paneha</em> -- 'let her remove her prostitution from her face' -- the call to repentance that underlies the lawsuit: the legal action is not final punishment but a call to amendment.</p>",
        "3": "<p><strong>Pen-achasot ha-imah</strong> -- 'or else I will strip her naked.' The warning of covenant punishment: <em>Ve-hitzagtiha ke-yom hullaledet</em> -- 'and expose her as on the day she was born.' Birth-nakedness -- total vulnerability and shame. <em>Ve-samtia ka-midbar</em> -- 'and make her like a wilderness.' The covenant curse of land desolation (Lev 26:33; Deut 28:23-24) is framed as the reversal of the Exodus gift: YHWH brought Israel from wilderness to fruitful land; covenant violation returns the land to wilderness. <em>Ve-hamittia ba-tzimmaon</em> -- 'and parched with thirst.' The images of aridity (wilderness, parched) contrast with the covenant promises of water, rain, and fruitful land (2:21-22).</p>",
        "4": "<p><strong>Ve-et-baneha lo arachem</strong> -- 'I will show no compassion to her children.' The children of the unfaithful mother (Israel) share in the judgment -- not because they are individually guilty, but because covenant unfaithfulness corrupts the entire household. <em>Ki benei zenutim hemmah</em> -- 'for they are children of unfaithfulness.' <em>Zenutim</em> (prostitutions/unfaithfulness) -- not merely the children of a prostitute but the offspring of a spiritually adulterous society. The punishment of children for parental sin raises the theodicy question that Ezekiel 18 addresses directly -- Hosea leaves the tension standing rather than resolving it, reflecting the corporate solidarity of the covenant.</p>",
        "5": "<p><strong>Ki zantah immam</strong> -- 'For their mother has been unfaithful.' The mother's statement is quoted: <em>Elekhah acharei meahavai</em> -- 'I will go after my lovers.' <em>Meatim</em> (my lovers, H157) -- the Baals and the fertility cult partners Israel pursued. The shocking claim: <em>Notenii lachmi u-meimi tzamri u-fishti shimni u-shiquvai</em> -- 'who give me my bread and my water, my wool and my flax, my oil and my drink.' Israel has attributed the covenant gifts (grain, wine, oil -- the standard triad of Deut 7:13) to the Baals rather than to YHWH. The diagnostic error is one of mis-attribution: the gifts are real but the giver is misidentified. This error is the root of idolatry as Hosea understands it.</p>",
        "6": "<p><strong>Lachen hineni sach et-darkech ba-sirim</strong> -- 'Therefore I will block her way with thorns.' The divine response to the pursuit of false lovers: YHWH blocks the paths with thorns (<em>sirim</em>, H5518) and builds a wall (<em>gadar</em>, H1447) so she cannot reach her destinations. The image is not primarily punitive but remedial -- the blocking is designed to redirect, not destroy. The thorns and wall prevent the prostitution from succeeding so that she might return to the first husband. This is the coercive mercy of the covenant: YHWH's frustration of Israel's idolatry as a means of bringing her back.</p>",
        "7": "<p><strong>Ve-ridefeah et-meahaveyha ve-lo tasiag otam</strong> -- 'She will chase after her lovers but not catch them.' The pursuit ends in failure: the Baals cannot be found when Israel seeks them. <em>Ve-biqqeshtam ve-lo timtza</em> -- 'she will seek them but not find them.' The failure of the false lovers is YHWH's doing through the wall and thorns of v.6. <em>Ve-amrah elkhah ve-ashuva el-ishi ha-rishon</em> -- 'then she will say, I will go and return to my first husband.' <em>Ishi ha-rishon</em> (my first husband) -- YHWH as the original marriage partner, the covenant relationship prior to the Baals. <em>Ki tov li az mi-attah</em> -- 'for it was better for me then than now.' The comparative judgment: the covenant life is better than the idolatrous life, even from the perspective of material provision. The return is motivated by experiential memory, not merely theological instruction.</p>",
        "8": "<p><strong>Ve-hi lo yadah ki anokhi natatti lah ha-dagan ve-ha-tirosh ve-ha-yitzhar</strong> -- 'She did not know that it was I who gave her the grain, the wine, and the oil.' The tragedy of ignorance: <em>Lo yadah</em> (she did not know) -- <em>yada</em> (H3045, to know) is the key verb of Hosea's theology. The 'knowledge of God' (<em>daath Elohim</em>) is not merely intellectual but covenantal -- to know YHWH is to recognize him as the source of all covenant gifts. Israel's idolatry is fundamentally an epistemological failure: she received good gifts but attributed them to the wrong giver. <em>Ve-chasef va-zahav hirbu lahem asher asu la-Baal</em> -- 'and who lavished on her silver and gold, which they used for Baal.' Even the wealth Israel used to craft idols was YHWH's gift. The idols were funded by the God they displaced.</p>",
        "9": "<p><strong>Lachen ashuv ve-laqachti degani be-ito ve-tiroshi be-moadо</strong> -- 'Therefore I will take back my grain when it ripens and my wine when it is ready.' YHWH's reclamation of the covenant gifts he gave: the possessive pronoun is emphatic -- <em>degani</em> (my grain), <em>tiroshi</em> (my wine) -- the gifts remain YHWH's even when given to Israel. Taking them back is the act of a husband removing the household provision from an unfaithful wife. <em>Ve-hitzalti tzamri ve-fishti le-khassot et-ervatah</em> -- 'I will reclaim my wool and my flax, which were used to cover her nakedness.' The exposure of nakedness (v.3) is the punishment; the removal of the covering garments is the instrument. The covenant covered Israel's shame; covenant violation means the covering is removed.</p>",
        "10": "<p><strong>Ve-attah agaleh et-navlutatah le-einei meahaveyha</strong> -- 'Now I will expose her shameful nakedness before her lovers.' <em>Navlut</em> (H5040, lewdness/shameful nakedness) -- public exposure as the covenant curse for unfaithfulness (cf. Ezek 16:37-39; Nah 3:5). The exposure before the lovers is the ultimate shame: those she sought to please will witness her punishment. <em>Ve-ish lo-yatzzilenah mi-yyadi</em> -- 'and no one will rescue her from my hand.' The powerlessness of the Baals: they cannot protect the one who worshipped them when YHWH acts in judgment. The false lovers provide nothing at the moment of crisis -- the exact opposite of YHWH's covenant protection.</p>",
        "11": "<p><strong>Ve-hishbatti kol-mesosah chagah chadshah ve-shabbatah</strong> -- 'I will put an end to all her celebrations -- her festivals, her new moon observances, her sabbaths.' The cessation of the cultic calendar is the withdrawal of covenant worship-structure. <em>Chag</em> (H2282, pilgrimage festival), <em>chodesh</em> (H2320, new moon), <em>Shabbat</em> (H7676, Sabbath) -- the three principal liturgical rhythms of Israel's covenant life. Their suspension is not mere punishment but the logical consequence of covenant dissolution: if the covenant is annulled, the covenant-ordered time cannot continue. The withdrawal of liturgical time mirrors the exile's disruption of sacred geography.</p>",
        "12": "<p><strong>Ve-hacharvoti gafnah ve-teenatah</strong> -- 'I will ruin her vines and her fig trees.' The specific crops named are the covenant gifts Israel attributed to the Baals (v.5). <em>Asher amrah etnan hemah li asher natenu li meahavai</em> -- 'which she said were the gifts her lovers gave her.' The ruin makes visible the falseness of her attribution: the Baals cannot sustain what YHWH withdraws. <em>Ve-samtim le-yaar</em> -- 'I will make them a forest.' Cultivated land reverting to wilderness -- the un-gardening of the covenant land. <em>Ve-akhalatan chayat ha-sadeh</em> -- 'and wild animals will devour them.' The wild animals represent the undoing of the agricultural order that covenant life maintains.</p>",
        "13": "<p><strong>Ve-faqadti aleha et-yemei ha-Baalim</strong> -- 'I will punish her for the days she burned incense to the Baals.' <em>Faqad</em> (H6485, to visit/appoint/punish) -- divine attention for judgment. <em>Asher tiqter lahem va-tadas nizmatah ve-cheliyatah va-telekh acharei meahaveyha</em> -- 'when she adorned herself with rings and jewelry and went after her lovers.' The adorning is the preparation for cult prostitution -- dressing for the lover, not the husband. <em>Ve-oti shakhachah</em> -- 'and forgot me.' <em>Shakach</em> (H7911, to forget) -- the opposite of <em>zachor</em> (to remember/be faithful). Forgetting YHWH is the active form of apostasy in Hosea: not merely ignorance but willful erasure of the covenant relationship. The verb is used eight times in Hosea.</p>",
        "14": "<p><strong>Lachen hineh anokhi mefateyah</strong> -- 'Therefore, behold, I will allure her.' The great reversal: after all the judgment language (vv.3-13), the divine strategy pivots to wooing. <em>Mefateyah</em> (H6601, to allure/entice/persuade) -- the same verb used in Exod 22:16 for seduction. YHWH woos his unfaithful wife back not by force but by persuasion. <em>Ve-holakhtiha ha-midbar</em> -- 'and bring her into the wilderness.' The wilderness is not only the place of judgment (v.3) but the place of covenant origin -- the Sinai wilderness where YHWH first spoke tenderly to Israel. The new exodus leads through a new wilderness encounter. <em>Ve-dibarti al-libah</em> -- 'and speak tenderly to her.' <em>Al-lev</em> (to the heart) -- the language of intimate reassurance (cf. Gen 50:21; Ruth 2:13; Isa 40:2). YHWH speaks to the heart, not merely to the legal standing, of his estranged wife.</p>",
        "15": "<p><strong>Ve-natatti lah et-keramehah mi-sham</strong> -- 'There I will give back her vineyards.' The restoration mirrors and reverses the judgment: the vineyards that were ruined (v.12) are given back. <em>Ve-et-emeq Akhor le-petach tiqvah</em> -- 'and make the Valley of Achor a door of hope.' <em>Akhor</em> (H5911, trouble/distress) -- the valley where Achan was executed for covenant violation (Josh 7:24-26). The place of covenant failure and punishment becomes the threshold of hope. The most troubled geography of Israel's past becomes the entrance to the restored future. <em>Ve-antetah sham ke-yemei neureiha</em> -- 'she will respond there as in the days of her youth.' <em>Anah</em> (H6030, to respond/answer) -- Israel's response to YHWH restored to the freshness of the Exodus. The honeymoon of Sinai recreated.</p>",
        "16": "<p><strong>Ve-hayah ba-yom ha-hu neum-YHWH</strong> -- 'In that day, declares the LORD.' The oracular formula marks the eschatological turning point. <em>Tiqrei Ishi</em> -- 'you will call me My Husband.' <em>Ishi</em> (H376+suffix, my man/husband) -- the term of intimate spousal address. <em>Ve-lo tiqrei-li od Baali</em> -- 'and you will no longer call me My Master/Lord.' <em>Baali</em> (H1168+suffix, my lord/Baal) -- the identical form used for the deity Baal and for a husband's authority title. The pun is deliberate: Israel will stop addressing YHWH with the title that sounds like the Baals' name. The new relationship will have a new relational vocabulary -- one of intimacy (<em>ishi</em>, husband) rather than hierarchy (<em>baali</em>, lord). The covenant is renewed on the terms of love rather than mere legal obligation.</p>",
        "17": "<p><strong>Va-hasiroti et-shemot ha-Baalim mi-piha</strong> -- 'For I will remove the names of the Baals from her lips.' The Baal names -- which were also spoken as divine titles in worship -- will be purged from Israel's language. The mouth that called on Baal will speak only of YHWH. <em>Ve-lo-yizzakheru od bi-shemam</em> -- 'and they will be mentioned no more.' The complete erasure of the Baals from covenant vocabulary. In Hosea's theology, naming and knowing are inseparable: to stop naming the Baals is to stop relating to them as if they existed. The purification of language is the prerequisite for the purification of worship.</p>",
        "18": "<p><strong>Ve-karati lahem berit ba-yom ha-hu</strong> -- 'In that day I will make a covenant for them.' The eschatological covenant encompasses the entire natural order. <em>Im-chayat ha-sadeh ve-im-of ha-shamayim ve-remes ha-adamah</em> -- 'with the wild animals, the birds of the sky, and the creatures of the ground.' The covenant with creation reverses the covenant curse of v.12 (wild animals devouring the land). <em>Ve-qeshet ve-cherev u-milchamah eshbor min-ha-aretz</em> -- 'and I will abolish the bow, the sword, and warfare from the land.' The bow that was broken in judgment (1:5) is now broken in peace: the same act has a completely different meaning in the restoration. <em>Ve-hishkavtim la-vetach</em> -- 'and I will make them lie down in safety.' The covenant peace: Israel resting secure in the land, as a flock under its shepherd.</p>",
        "19": "<p><strong>Ve-erastikh li le-olam</strong> -- 'I will betroth you to me forever.' The triple betrothal formula (vv.19-20) is the pinnacle of Hosea's restoration promise. <em>Aras</em> (H781, to betroth) -- the formal engagement that precedes marriage; YHWH proposes a new beginning to the covenant marriage, starting from engagement rather than from the existing marital state. <em>Le-olam</em> (H5769, forever/into the age) -- the betrothal will not be temporary or conditional in the way the Sinai covenant was. <em>Ve-erastikh li be-tzedeq u-ve-mishpat u-ve-chesed u-ve-rachamim</em> -- 'I will betroth you in righteousness and justice, in covenant loyalty and compassion.' Four covenant attributes are the dowry of the new marriage: <em>tzedeq</em> (righteousness), <em>mishpat</em> (justice), <em>chesed</em> (covenant loyalty), <em>rachamim</em> (compassion/mercy). These are the character-qualities that the Sinai covenant's institutional forms were meant to express -- now given as the basis of relationship itself.</p>",
        "20": "<p><strong>Ve-erastikh li be-emunah</strong> -- 'I will betroth you in faithfulness.' <em>Emunah</em> (H530, faithfulness/reliability/steadfastness) -- the quality of being dependable over time; the same root as <em>amen</em>. The fifth attribute of the new betrothal covenant. <em>Ve-yadaat et-YHWH</em> -- 'and you will know the LORD.' The climactic result of the five-fold betrothal is knowledge of YHWH -- <em>daath YHWH</em>. This is Hosea's central term: the covenant intimacy that Israel abandoned (4:1, 6) is the promised outcome of the restoration. The knowledge of God is not merely intellectual information but the experiential intimacy of a restored marriage. Paul's statement 'I know him whom I have believed' (2 Tim 1:12) and John's 'this is eternal life, that they know you, the only true God' (John 17:3) stand in Hosea's tradition.</p>",
        "21": "<p><strong>Ve-hayah ba-yom ha-hu aeneh neum-YHWH</strong> -- 'In that day I will respond, declares the LORD.' <em>Anah</em> (H6030, to respond/answer) -- YHWH initiates the chain of responses that will restore the broken order. <em>Aeneh et-ha-shamayim ve-hem yaanou et-ha-aretz</em> -- 'I will respond to the heavens, and they will respond to the earth.' A cascade of responses: YHWH speaks to the heavens, heavens respond to earth, earth responds to crops. The creation order, broken by the covenant curse (4:3: the land mourns), is restored by YHWH's covenantal faithfulness flowing through the creation hierarchy. The agricultural provision that Israel attributed to the Baals (v.5) is restored as a gift transparently from YHWH through the created order.</p>",
        "22": "<p><strong>Ve-ha-aretz taaneh et-ha-dagan ve-et-ha-tirosh ve-et-ha-yitzhar</strong> -- 'and the earth will respond to the grain, the wine, and the oil.' The triad of covenant agricultural gifts (dagan, tirosh, yitzhar) that Israel attributed to Baal (v.5) now flow from YHWH through the responsive creation order. <em>Ve-hem yaanou et-Yizreel</em> -- 'and they will respond to Jezreel.' The name Jezreel ('God sows') becomes the climactic term: what began as the name of judgment (1:4-5) ends as the name of agricultural restoration. God sows the seed; the chain of cosmic response produces the harvest; Jezreel is both the people who were scattered and re-sown and the land that produces the grain. The judgment name becomes the restoration name.</p>",
        "23": "<p><strong>Ve-zara'tiha li ba-aretz</strong> -- 'I will plant her for myself in the land.' <em>Zara</em> (H2232, to sow/plant) -- the literal fulfillment of Jezreel ('God sows'). YHWH personally sows Israel back into the covenant land after the exile-scattering. <em>Ve-richamti et-Lo-Ruhamah</em> -- 'and I will show mercy to the one called Lo-ruhamah.' The daughter whose name denied compassion is now given compassion -- the passive reversal of the Lo-ruhamah sentence. <em>Ve-amarti le-Lo-Ammi ammi atah</em> -- 'and I will say to Lo-ammi, You are my people.' The greatest reversal: the dissolution of the covenant formula in 1:9 is undone. 'You are my people' reinstates the broken covenant. <em>Ve-hu yomar Elohai</em> -- 'and he will say, My God.' The bilateral response: YHWH says 'my people'; Israel says 'my God.' Paul quotes this verse in Rom 9:25 for Gentile inclusion: the covenant restoration language applies to all who were 'not my people' and are now included in Christ.</p>"
    },
    "3": {
        "1": "<p><strong>Va-yomer YHWH elai</strong> -- 'Then the LORD said to me.' Ch 3 is the prose companion to ch 1-2's prophetic poetry: Hosea's renewed experience of redemption mirrors YHWH's covenant renewal. <em>Lekh ahav ishah ahuvat rea ve-naafet</em> -- 'Go again, love a woman who is loved by another man and is an adulteress.' <em>Ahav</em> (H157, to love) is the command -- love is not merely feeling but a covenantal act of will. The woman is simultaneously loved by another (<em>rea</em>, a companion/friend) and an adulteress (<em>naafet</em>). <em>Ka-ahavat YHWH et-benei Yisrael ve-hem penim el-elohim acherim</em> -- 'just as YHWH loves the children of Israel, though they turn to other gods.' The analogy is explicit: Hosea's continuing love for the unfaithful Gomer enacts YHWH's continuing love for unfaithful Israel. Love is not conditional on faithfulness; it persists through the faithlessness.</p>",
        "2": "<p><strong>Va-ekrehah li bi-asah asar keseph</strong> -- 'So I bought her back for fifteen pieces of silver.' <em>Karah</em> (H3739, to buy/acquire) -- a commercial term for purchasing or hire. The price of fifteen pieces of silver plus agricultural goods (a homer and a half of barley) is approximately half the slave price (thirty pieces of silver, Exod 21:32). The exact amount has been interpreted as indicating that Gomer had fallen into debt-slavery or cult prostitution and Hosea redeemed her at the going market rate. The redemption price -- less than a slave's value -- anticipates the humiliated state of Israel in exile and YHWH's redemption of a people who have become worthless by covenant violation.</p>",
        "3": "<p><strong>Va-omar eleha yamim rabbim teshevi li</strong> -- 'And I said to her, You must stay with me for many days.' The terms of the restored relationship are strict: no prostitution (<em>lo tiznei</em>), no intercourse with another (<em>ve-lo tihyi le-ish</em>), and -- remarkably -- abstinence from Hosea himself (<em>ve-gam anokhi elayikh</em>). The restoration requires a period of waiting and purification before full marital relations are restored. This mirrors the prophetic word about Israel's period of exile: many days without king, prince, sacrifice, pillar -- the institutions of national life suspended during the purification. The waiting is not abandonment but the preparation for full restoration.</p>",
        "4": "<p><strong>Ki yamim rabbim yeshvu benei-Yisrael</strong> -- 'For the children of Israel will live for many days without a king, without a ruler, without a sacrifice, without a pillar, without an ephod or teraphim.' The Hosea-Gomer waiting period is the key to the verse: the suspension of all Israel's political and cultic institutions parallels the suspension of the marital relationship. <em>Melekh ve-sar</em> (king and prince) -- the political institutions. <em>Zevach ve-matzevah</em> (sacrifice and pillar) -- the cultic institutions, including both legitimate (<em>zevach</em>) and syncretistic (<em>matzevah</em>, sacred pillar). <em>Efod ve-terafim</em> (ephod and teraphim) -- oracular objects, both legitimate and illegitimate. The exile strips Israel of both covenant-proper and syncretistic religion -- a total suspension that prepares for the purified restoration.</p>",
        "5": "<p><strong>Acharei yashuvu benei-Yisrael</strong> -- 'Afterward the children of Israel will return.' <em>Shub</em> (H7725, to return/repent/turn back) -- the key word for both physical return from exile and spiritual repentance. <em>U-viqshu et-YHWH Eloheihem ve-et David malkam</em> -- 'and seek the LORD their God and David their king.' The messianic expectation: a future Davidic king who unites the people under YHWH (cf. Jer 30:9; Ezek 34:23-24; 37:24-25). 'David their king' cannot refer to the historical David (long dead); it points to the expected Davidic heir who will restore the united kingdom. The NT identification: Jesus of the house of David, born in Bethlehem. <em>Ve-pachadu el-YHWH ve-el-tuvo be-acharit ha-yamim</em> -- 'they will come trembling to the LORD and to his goodness in the latter days.' <em>Acharit ha-yamim</em> (the latter days/the end of days) -- the eschatological frame: this is not merely a historical restoration but the final-age return.</p>"
    },
    "4": {
        "1": "<p><strong>Shimou devar-YHWH benei Yisrael</strong> -- 'Hear the word of YHWH, O children of Israel.' The <em>riv</em> (covenant lawsuit) genre is announced: YHWH has a case against the land's inhabitants. <em>Ki riv la-YHWH im-yoshvei ha-aretz</em> -- 'for YHWH has a case against the inhabitants of the land.' <em>Ki ein emet ve-ein chesed ve-ein daath Elohim ba-aretz</em> -- 'for there is no faithfulness (<em>emet</em>), no covenant loyalty (<em>chesed</em>), and no knowledge of God (<em>daath Elohim</em>) in the land.' The three covenant virtues are listed as absent. <em>Emet</em> (H571, truth/faithfulness) -- dependability in covenant relationship. <em>Chesed</em> (H2617, covenant love/loyalty) -- the quality YHWH repeatedly displays and Israel fails to match. <em>Daath Elohim</em> (knowledge of God) -- the relational intimacy and covenantal awareness that Hosea has established as the center of YHWH's desire (6:6). All three are missing simultaneously: the social, relational, and theological dimensions of covenant life have collapsed.</p>",
        "2": "<p><strong>Aloh ve-kachesh ve-ratzoch ve-ganav ve-naof</strong> -- 'There is cursing, lying, murder, stealing, and adultery.' The five sins roughly parallel the second table of the Decalogue (commandments 6-9, with oaths added). <em>Paratzto</em> -- 'they break all bounds.' <em>Ve-damim be-damim nagau</em> -- 'and bloodshed follows bloodshed.' The image of blood touching blood: violence so pervasive that each act of murder creates the conditions for the next. The social fabric that the covenant was designed to protect has been torn through completely. The lawsuits and moral failures are not isolated incidents but a systemic collapse.</p>",
        "3": "<p><strong>Al-ken teeval ha-aretz</strong> -- 'Therefore the land mourns.' <em>Aval</em> (H56, to mourn/wither) -- the land itself participates in grief at the covenant violation. The covenant is not merely a human-divine agreement but has cosmic dimensions: the land's fruitfulness and the creation order are bound up with covenant fidelity (cf. Lev 26:20; Jer 12:4). <em>Ve-umlag kol-yoshev bah</em> -- 'and all who live in it waste away.' <em>Be-chayat ha-sadeh u-ve-of ha-shamayim ve-gam degei ha-yam yeasaphu</em> -- 'together with the animals of the field, the birds of the sky, and even the fish of the sea.' The three realms of creation (land, sky, sea) are all affected. The ecological collapse is the covenant curse made visible in the natural world -- an anticipation of the creation-groaning theology of Rom 8:19-22.</p>",
        "4": "<p><strong>Akh ish al-yarev ve-al-yochiach ish</strong> -- 'Yet let no one accuse or rebuke another.' The irony of a society in which lawsuit is the dominant mode of interaction (v.1, riv) yet no one has standing to accuse another -- because all are equally guilty. <em>Ve-ammekha ki-merivei kohen</em> -- 'for your people are like those who bring charges against a priest.' The sacerdotal legal immunity -- or the inversion of the priestly role from teacher to defendant -- the priest who should adjudicate the law has become its transgressor. The verse is difficult grammatically and has multiple interpretive options; the MKT follows the reading that the people's condition resembles constant litigation against their own leaders.</p>",
        "5": "<p><strong>Ve-kashalta ha-yom ve-kashalta gam-navi immekha lailah</strong> -- 'You stumble in the daylight; the prophet stumbles with you in the night.' The stumblings of the people and the prophet are simultaneous: both are failing. <em>Ve-dammiti immekha</em> -- 'and I will destroy your mother.' The 'mother' is the national community -- Israel as mother of the individual Israelites (cf. 2:2). The priests and prophets who should have provided guidance through the darkness are themselves stumbling.</p>",
        "6": "<p><strong>Nidmu ammi mi-beli ha-daath</strong> -- 'My people are destroyed for lack of knowledge.' The most famous verse in Hosea. <em>Nidam</em> (H1826, destroyed/silenced/cut off) -- total annihilation. The cause: <em>mi-beli ha-daath</em> (for lack of knowledge). <em>Daath</em> (H1847, knowledge) is the relational knowing that the covenant relationship produces -- not merely information but experiential intimacy with YHWH and his Torah. <em>Ki attah ha-daath maasta</em> -- 'Because you have rejected knowledge.' The rejection is active: Israel did not merely fail to acquire knowledge, she pushed it away. <em>Va-emmaasekha mi-kehannei li</em> -- 'I will reject you from being my priest.' The consequence is proportionate: those who reject the priestly vocation of teaching Torah are themselves rejected from the priesthood. <em>Ve-tishkach Torat Elohekha</em> -- 'and since you have forgotten the Torah of your God' -- the active forgetting of Torah is the mechanism of the knowledge-failure.</p>",
        "7": "<p><strong>Ke-rabbam ken chatu-li</strong> -- 'The more they multiplied, the more they sinned against me.' The paradox of prosperity and sin: the growth of the population (the Abrahamic blessing) became the occasion for multiplied transgression rather than multiplied fidelity. <em>Kevodim be-qalon amir</em> -- 'they exchanged their glory for shame.' <em>Kavod</em> (H3519, glory/honor) -- the glory of the covenant relationship with YHWH; <em>qalon</em> (H7036, shame/dishonor). The exchange formula is the prophetic vocabulary for idolatry: trading the genuine article for an inferior substitute (cf. Jer 2:11; Rom 1:23). What was glorious has been traded for something shameful.</p>",
        "8": "<p><strong>Chatat ammi yokhelu</strong> -- 'They feed on the sins of my people.' The priests' economic dependence on the sin offering (<em>chatat</em>, H2403) has created a perverse incentive: more sin = more priestly income. <em>Ve-el avonam yissu nafsham</em> -- 'they are greedy for their iniquity.' The priestly institution that was supposed to mediate forgiveness has become structurally committed to perpetuating the sin that funds it. This is a systemic critique of corrupt institutionalized religion: the very mechanisms of atonement become the instruments of exploitation when the priests profit from transgression.</p>",
        "9": "<p><strong>Ve-hayah ke-am ke-kohen</strong> -- 'And it will be: like people, like priest.' The moral leveling: the priestly distinction is dissolved by the priests' participation in the people's sin. <em>U-faqadti alav derakaiv</em> -- 'I will punish them both for their ways.' <em>Ve-ma'alalehem ashiv lo</em> -- 'and repay them for their deeds.' The lex talionis principle of covenant justice: the punishment mirrors the sin. When priests become indistinguishable from the sinful people, they share the people's judgment.</p>",
        "10": "<p><strong>Ve-akhlu ve-lo yisbau</strong> -- 'They will eat but not be satisfied.' The covenant curse of unfulfillment: abundance without satisfaction (Lev 26:26; Mic 6:14). <em>Hiznu ve-lo yifrotzu</em> -- 'they will pursue prostitution but not flourish.' The fertility-cult logic fails: they pursue the Baals for fertility and get barrenness. <em>Ki et-YHWH azvu</em> -- 'because they have abandoned the LORD.' The abandonment of YHWH is the single cause of the double curse: unsatisfied hunger and barren sexuality.</p>",
        "11": "<p><strong>Zenut ve-yayin ve-tirosh yiqach-lev</strong> -- 'Prostitution, wine, and new wine take away the understanding.' <em>Lev</em> (H3820, heart/mind/understanding) -- the cognitive and moral center. Three intoxicants: sexual immorality, old wine, and new wine. The loss of <em>lev</em> is the loss of the capacity for <em>daath</em> -- the knowledge that Hosea holds as the central covenant virtue. Moral intoxication removes the very faculty needed for covenant fidelity.</p>",
        "12": "<p><strong>Ammi be-etzo yishal</strong> -- 'My people consult a piece of wood.' The absurdity of wood-divination: a stick answers the questions that Torah should answer. <em>Ve-maqlo yagid lo</em> -- 'and their divining rod gives them answers.' <em>Ki ruach zenutim hitah</em> -- 'for a spirit of prostitution has led them astray.' <em>Ruach zenutim</em> (spirit of prostitution/unfaithfulness) -- not merely a social tendency but a spiritual power that drives Israel away from YHWH. The 'spirit of prostitution' appears three times in Hosea (4:12; 5:4) as the animating principle of Israel's idolatry. <em>Va-yiznu mi-tachat Eloheihem</em> -- 'and they have played the whore away from under their God.' The preposition <em>mi-tachat</em> (from under) -- they were under YHWH's covenant authority and have departed from under it.</p>",
        "13": "<p><strong>Al-rashei he-harim yezabechu ve-al-ha-gevot yeqatteru</strong> -- 'They sacrifice on the mountaintops and burn incense on the hills.' The high-place cult: mountaintop worship was the standard form of Canaanite religion that Israel absorbed. <em>Tachat alon vi-livneh ve-elah ki tov tzilah</em> -- 'under oak and poplar and terebinth trees, because the shade is good.' The practical attraction of shade and elevation -- religion accommodated to physical comfort. <em>Al-ken tiznena benoteikem ve-khaloteikem tena'afnah</em> -- 'therefore your daughters commit prostitution, and your daughters-in-law commit adultery.' The social consequence of cultic prostitution: the normalization of sexual immorality at the sanctuary spreads to the household. The cult's sexual sin is not contained in the sacred space but shapes the entire social fabric.</p>",
        "14": "<p><strong>Lo-afqod al-benoteikem ki tiznena</strong> -- 'I will not punish your daughters when they commit prostitution.' The seeming double standard is explained: <em>Ve-ha-anashim im-ha-zedeshot yefalelu</em> -- 'because the men themselves go off with the cult prostitutes.' The men who frequent the cult prostitutes cannot then punish the daughters who become cult prostitutes. The male leadership's participation in the cult is the cause of the female population's sexual sin. YHWH will not punish the symptom without addressing the cause. <em>Ve-am lo-yavin yillavet</em> -- 'a people without understanding comes to ruin.' The absence of <em>binah</em> (understanding) -- related to <em>daath</em> -- is the root cause of the social-moral collapse.</p>",
        "15": "<p><strong>Im-zoneh attah Yisrael</strong> -- 'Though you, Israel, commit adultery.' The northern kingdom's apostasy is addressed with a warning to Judah: do not be infected by the northern idolatry. <em>Al-yeasham Yehudah</em> -- 'do not let Judah become guilty.' <em>Ve-al-tavu ha-Gilgal</em> -- 'do not go to Gilgal.' Gilgal was a legitimate cultic site that had become associated with syncretism (cf. Amos 5:5). <em>Ve-al-talu Beit-Aven</em> -- 'or journey up to Beth-aven.' <em>Beth-aven</em> (house of wickedness/futility) is Hosea's contemptuous renaming of <em>Beth-el</em> (house of God, H1008) -- the northern sanctuary established by Jeroboam I with its golden calves (1 Kgs 12:29). The sacred name has been desecrated by the false cult.</p>",
        "16": "<p><strong>Ki ke-farah sareirah sarer Yisrael</strong> -- 'For Israel has become stubborn, like a stubborn heifer.' <em>Sareirah</em> (H5637, stubborn/obstinate) -- the animal image of the ox that refuses the yoke. In Deuteronomy, the 'stiff-necked' (<em>qesheh-oref</em>) people resist divine direction. The heifer that will not yield to the harness cannot be used to plow -- she is useless for the covenant labor. <em>Attah yirenhem YHWH ke-keves be-merchav</em> -- 'Can the LORD now pasture them like a lamb in open country?' The rhetorical question implies that a stubborn heifer cannot be safely pastured -- the covenant relationship of divine shepherding requires a responsive flock.</p>",
        "17": "<p><strong>Chavur atzabbim Efrayim</strong> -- 'Ephraim is attached to idols.' <em>Chavar</em> (H2266, to be joined/attached/bound) -- the bond to idols is as strong as the covenant bond to YHWH should be, but directed at the wrong object. <em>Hanacha lo</em> -- 'leave him alone.' The divine withdrawal: YHWH steps back from striving with Ephraim and allows the full consequences of idolatry to unfold. The 'leave him alone' anticipates Paul's description of divine judgment as 'God gave them up' (Rom 1:24, 26, 28) -- the withdrawal of restraint as the beginning of judgment.</p>",
        "18": "<p><strong>Sar savaam</strong> -- 'Their drinking bouts are over.' The translation is uncertain (<em>sar</em> can mean 'ruler/prince' or 'to turn aside'); the MKT reads the carousing that has characterized the cult as coming to an end. <em>Hiznu hiznah</em> -- 'they have given themselves completely to prostitution.' <em>Ahevu hev hevish magineha</em> -- 'their rulers dearly love shame.' The political leadership's love of the shameful practices makes the corruption systemic from the top down. What the priests do (v.8-10), the rulers amplify.</p>",
        "19": "<p><strong>Tzarar ruach otah bi-khanafehah</strong> -- 'A wind will sweep them away in its wings.' <em>Ruach</em> (H7307, wind/spirit) -- the same word used for the 'spirit of prostitution' in v.12; now the wind is the instrument of judgment, sweeping away the idolaters in its wings. <em>Ve-yevoshu mi-zivchotam</em> -- 'and they will be ashamed of their sacrifices.' The shame that idolatry promised to avoid (social disgrace, cultic impurity) is precisely what idolatry delivers. The sacrifices at the high places, which were meant to win the Baals' favor, become the objects of shame when the Baals prove powerless.</p>"
    },
    "5": {
        "1": "<p><strong>Shimou zot ha-kohanim</strong> -- 'Hear this, O priests!' Ch 5 opens with a triple summons: priests, house of Israel, and the royal house are all called to account. <em>Ve-haqshivu beit-Yisrael</em> -- 'Listen, O house of Israel!' <em>Ve-beit ha-melekh ha-azinu</strong> -- 'Give ear, O house of the king!' All three leadership institutions -- cultic, national, and royal -- bear responsibility. <em>Ki lakhem ha-mishpat</em> -- 'for the judgment is against you.' <em>Mishpat</em> (H4941, judgment/justice) -- the covenant lawsuit reaches its verdict. <em>Ki pahh hayitem le-Mitzpah</em> -- 'for you have been a snare at Mizpah.' Mizpah and Tabor were cultic and administrative centers; the leaders stationed there to guide Israel have become traps (H6341, pahh) -- snares set for the people rather than guides.</p>",
        "2": "<p><strong>Ve-shachata ha-sheetim he-imiku</strong> -- 'The rebels are deep in their corruption.' The slaughter pits and the depth of rebellion. <em>Va-anochi musar le-kulam</em> -- 'though I have been a discipline to all of them.' YHWH has provided ongoing correction and instruction -- the leadership has refused to learn from it. The divine pedagogy of history (the plagues, the desert wandering, the judges' cycles) has gone unheeded by those who should have taught its lessons.</p>",
        "3": "<p><strong>Ani yadati Efrayim ve-Yisrael lo-nichad mimmenni</strong> -- 'I know Ephraim, and Israel is not hidden from me.' YHWH's knowledge (<em>yada</em>) is comprehensive and covenantal -- he knows Ephraim with the intimacy of the covenant partner who sees everything. <em>Ki attah hizne'atah Efrayim</em> -- 'Ephraim, you have now played the whore.' The use of the perfect tense suggests completed, settled adultery. <em>Nitma Yisrael</em> -- 'Israel has become defiled.' <em>Nitma</em> (H2930, to be made unclean/defiled) -- the ritual impurity that results from idolatry. Israel's spiritual adultery has produced a state of defilement comparable to ritual impurity.</p>",
        "4": "<p><strong>Lo-yitnu maleleihem la-shuv el-Eloheihem</strong> -- 'Their deeds do not permit them to return to their God.' The sin has created its own momentum: the <em>maleleihem</em> (their deeds) actively prevent repentance. <em>Ki ruach zenutim be-qirbam</em> -- 'for a spirit of prostitution is within them.' The <em>ruach zenutim</em> of 4:12 returns: not merely external behavior but an internalized spirit that drives away from YHWH. <em>Ve-et-YHWH lo yadau</em> -- 'and they do not know the LORD.' The failure of knowledge (<em>daath</em>) appears again as the consequence and cause simultaneously: they do not know YHWH, so the spirit of prostitution fills the vacuum; the spirit of prostitution prevents them from knowing YHWH. The cycle is self-reinforcing.</p>",
        "5": "<p><strong>Ve-anah gaon Yisrael be-fanav</strong> -- 'Israel's arrogance testifies against him to his face.' <em>Gaon</em> (H1347, pride/arrogance/majesty) -- the pride that should have been directed toward YHWH (his glory/majesty) has been redirected to Israel itself. The arrogance becomes self-accusing: <em>ve-Yisrael ve-Efrayim yikkashelu ba-avonam</em> -- 'Israel and Ephraim will stumble in their iniquity.' <em>Ve-kashhal gam-Yehudah immam</em> -- 'and Judah will stumble with them.' The judgment expands: Judah's warning (4:15) has not been heeded, and Judah too will share in the northern kingdom's fate.</p>",
        "6": "<p><strong>Be-tzonam u-veqqaram yelekhu le-vaqesh et-YHWH ve-lo yimtzau</strong> -- 'They will go with their flocks and herds to seek the LORD, but they will not find him.' The seeking of YHWH with cultic offerings (flocks and herds) without covenant heart-knowledge produces religious activity with no access to God. <em>Chalatz mehehem</em> -- 'He has withdrawn from them.' <em>Chalatz</em> (H2502, to withdraw/draw out) -- YHWH removes himself from the cultic encounter. The sacrifices continue; YHWH is absent. This is the prophetic critique of ex opere operato religion: ritual performance without covenant relationship cannot summon the divine presence.</p>",
        "7": "<p><strong>Be-YHWH bagadu ki-vanim zarim yaladu</strong> -- 'They have been unfaithful to the LORD, because they have borne illegitimate children.' <em>Bagad</em> (H898, to deal treacherously/be unfaithful) -- the same verb used for Gomer's treachery (2:2). The 'illegitimate children' (<em>banim zarim</em>) are those born of the religious syncretism: the mixed offspring of YHWH-worship and Baal-worship. <em>Attah yokhal otam yareach et-chelqehem</em> -- 'Now the new moon will devour them along with their fields.' The new moon festival (<em>chodesh</em>, cf. 2:11) that was suspended as covenant judgment now becomes the instrument of devouring -- the sacred time becomes the time of destruction.</p>",
        "8": "<p><strong>Tiqu shofar be-Giveah chatzotzera ba-Ramah</strong> -- 'Sound the ram's horn in Gibeah, the trumpet in Ramah.' The war alarm -- <em>shofar</em> (H7782, ram's horn) and <em>chatzotzera</em> (H2689, trumpet) -- signals imminent Assyrian invasion. Gibeah and Ramah are towns on the southern border of the northern kingdom (or the northern border of Benjamin), the path of invasion. <em>Hariu Beit-Aven acharekha Binyamin</em> -- 'raise the battle cry at Beth-aven: Behind you, Benjamin!' The invasion sweeps from north to south; Benjamin (in Judah's territory, south of Ephraim) is warned that the army is behind them. The cult site of Beth-aven (the renamed Bethel, 4:15) will not protect Israel when Assyria comes.</p>",
        "9": "<p><strong>Efrayim le-shammah tihyeh be-yom tokhechah</strong> -- 'Ephraim will be laid waste on the day of punishment.' <em>Shammah</em> (H8047, desolation/horror) -- the total devastation of the northern kingdom. <em>Ba-shivtei Yisrael hodati nemannah</em> -- 'among the tribes of Israel I have declared what is certain.' YHWH's word is reliable (<em>nemannah</em>, H539, trustworthy/faithful): the coming judgment is certain because it rests on YHWH's covenant word.</p>",
        "10": "<p><strong>Hayu sarei Yehudah ke-massigei gevul</strong> -- 'The princes of Judah have become like those who move boundary stones.' The boundary stone (<em>gevul</em>, H1366) was protected by covenant law (Deut 19:14; 27:17); moving it was a form of fraud and theft. Judah's princes are using their authority to expand their own territory at others' expense -- the social-justice critique applied to the southern kingdom. <em>Aleihem eshpokh ka-mayim evrati</em> -- 'I will pour out my wrath on them like water.' The wrath poured like water is catastrophic and all-encompassing -- not a measured response but an overwhelming flood.</p>",
        "11": "<p><strong>Ashuq Efrayim rashatz ba-mishpat</strong> -- 'Ephraim is oppressed and crushed in justice.' <em>Ashaq</em> (H6231, to oppress/wrong) and <em>ratzatz</em> (H7533, to crush/shatter) -- double verbs of violence applied to the judgment of Ephraim. <em>Ki hoel halakh acharei tzav</em> -- 'because he was determined to pursue worthless idols.' <em>Tzav</em> (H6673) is debated: it may mean 'filth/dung' (a contemptuous word for idols), 'human command' (following human rather than divine authority), or 'empty things.' The MKT reads 'worthless idols.' Ephraim's determined pursuit of idolatry has resulted in the crushing oppression that his covenant faithfulness would have prevented.</p>",
        "12": "<p><strong>Ve-anokhi ka-ash le-Efrayim</strong> -- 'I will be like a moth to Ephraim.' The divine judgment imagery shifts from violent (lion, v.14) to slow and insidious: a moth (<em>ash</em>, H6211) eating fabric -- invisible, gradual, but ultimately destructive. <em>Ve-ka-raqav le-veit Yehudah</em> -- 'and like rot to the house of Judah.' <em>Raqav</em> (H7538, rot/dry rot) -- the slow decay that hollows out a structure before it collapses. The judgment of both kingdoms is described as slow decay rather than sudden catastrophe -- the long decline of covenant faithlessness before the Assyrian blow.</p>",
        "13": "<p><strong>Va-yar Efrayim et-cholyo</strong> -- 'When Ephraim saw his sickness.' The political response to the covenant decay is to seek foreign alliance rather than divine healing. <em>Ve-Yehudah et-mazzo</em> -- 'and Judah saw his wound.' <em>Va-yelekh Efrayim el-Ashshur</em> -- 'Ephraim turned to Assyria.' The northern kingdom's appeal to Assyria for political security is documented historically (2 Kings 15:19; 17:3-4). <em>Ve-yishlach el-melek yarev</em> -- 'and sent to the great king.' <em>Melekh yarev</em> (the great/warring king) -- an epithet for the Assyrian king; possibly a transliteration of the Assyrian royal title. <em>Ve-hu lo yukhal lirpa lakhem</em> -- 'but he is not able to heal you.' The Assyrian king cannot cure what only YHWH can heal: the covenant sickness requires the covenant physician.</p>",
        "14": "<p><strong>Ki anokhi ka-shachal le-Efrayim</strong> -- 'For I will be like a lion to Ephraim.' The image shifts from moth (v.12) to lion (<em>shachal</em>, H7826, fierce/great lion): slow decay gives way to sudden violent destruction. <em>Ve-ka-kefir le-veit Yehudah</em> -- 'like a young lion to the house of Judah.' <em>Kefir</em> (H3715, young lion/growing lion) -- the energy and power of a young predator. <em>Ani ani etaref ve-eelekh essa ve-ein matzil</em> -- 'I myself will tear them apart and go away; I will carry off and no one will rescue.' The divine withdrawal after judgment: YHWH attacks, tears, carries off, and departs -- leaving the wounded prey with no rescuer. The same YHWH who refused to be found when sought with flocks (v.6) now actively pursues in judgment.</p>",
        "15": "<p><strong>Elekh ashuva el-meqomi</strong> -- 'I will return to my place.' YHWH withdraws to the divine dwelling (his 'place') after the judgment -- the same hidden God of Isa 45:15. <em>Ad asher-yeshlemu ve-viqshu fanai</em> -- 'until they acknowledge their guilt and seek my face.' The withdrawal is purposive: it creates the conditions for genuine repentance. <em>Yeshlemu</em> (H816, to be guilty/suffer punishment) -- acknowledging guilt is the first step of return. <em>Be-tzar lahem yeshachshuni</em> -- 'in their distress they will earnestly seek me.' The distress of Assyrian conquest will drive what prosperity and security could not: genuine seeking of YHWH. The hiddenness of God creates the longing that the divine presence does not.</p>"
    },
    "6": {
        "1": "<p><strong>Lekhu ve-nashuva el-YHWH</strong> -- 'Come, let us return to the LORD.' Ch 6 opens with Israel's response to 5:15 -- the seeking that YHWH awaited. Whether this is genuine repentance or shallow liturgy is the great question the chapter raises (v.4 casts doubt on its depth). <em>Nashuva</em> (H7725, let us return) -- the first person plural cohortative of <em>shub</em>, the key repentance word. <em>Ki hu taraf ve-yirpenu</em> -- 'He has torn us, but he will heal us.' The acknowledgment that YHWH is the source of both the wound and the healing. <em>Yakh ve-yachavsenu</em> -- 'he has wounded us, but he will bind up our wounds.' The verb <em>chavash</em> (H2280, to bind up/bandage) is used of medical care; YHWH as the physician who diagnoses, wounds, and heals.</p>",
        "2": "<p><strong>Yechayenu mi-yomayim ba-yom ha-shelishi yeqimenu</strong> -- 'After two days he will revive us; on the third day he will raise us up.' The temporal formula -- two days, then the third day -- has generated enormous NT interest because of its resonance with the resurrection. <em>Yechayenu</em> (H2421, he will revive us/give us life) and <em>yeqimenu</em> (H6965, raise us up) -- both verbs are used in the NT for resurrection. Whatever the original referent (the short period of national judgment before covenant restoration), the language anticipates the resurrection idiom. Paul's citation in 1 Cor 15:4 ('he was raised on the third day in accordance with the Scriptures') draws on this broader OT pattern of third-day divine intervention and vindication (cf. Gen 22:4; Exod 19:11; Josh 1:11; 2 Kgs 20:5). <em>Ve-nichyeh le-fanav</em> -- 'and we will live before him.' Covenant life lived in YHWH's presence: the goal of the return.</p>",
        "3": "<p><strong>Ve-neda nirdefa ladat et-YHWH</strong> -- 'Let us press on to know the LORD.' <em>Radaf</em> (H7291, to pursue/press on after) -- the verb of pursuit used elsewhere for chasing enemies is here applied to the knowledge of God. <em>Ke-shachar nakhon motzao</em> -- 'his appearing is as certain as the dawn.' The dawn (<em>shachar</em>, H7837) is the reliable daily renewal -- YHWH's self-revelation is as dependable as the sunrise. <em>Ve-yavo chameishem la-matar</em> -- 'He will come to us like the rain.' The rain (<em>matar</em>) and the latter rain (<em>maqosh</em>) are the covenant blessings of agricultural provision (Deut 11:14; Joel 2:23). YHWH's coming is like the seasonal rains that make the land fruitful -- the comparison grounds divine revelation in the covenant agricultural promise.</p>",
        "4": "<p><strong>Mah easeh lekha Efrayim mah easeh lekha Yehudah</strong> -- 'What shall I do with you, Ephraim? What shall I do with you, Judah?' The divine perplexity -- not ignorance but exasperation. The rhetorical question expresses the pathos of YHWH's love frustrated by repeated covenant failures. <em>Ve-chasedkhem ke-anan-boqer</em> -- 'your love is like a morning cloud.' <em>Chesed</em> is here Israel's reciprocal covenant love (not YHWH's) -- and it evaporates like the morning cloud (<em>anan-boqer</em>). <em>Ve-ka-tal mashkim holekh</em> -- 'like the morning dew that disappears early.' The dew is beautiful, refreshing, and transient. Israel's repentance (vv.1-3) is precisely this: lovely in expression, gone before noon. This verse casts retrospective doubt on the sincerity of 6:1-3 and confirms that the issue is not a lack of religious language but a lack of covenant depth.</p>",
        "5": "<p><strong>Al-ken chatzavti ba-neviim haragtim be-imrei fi</strong> -- 'Therefore I have hewn them down by the prophets; I have slain them by the words of my mouth.' The prophetic word as the instrument of divine judgment: YHWH's words spoken through the prophets are the sword that slays and the chisel that hews. <em>Ve-mishpatekha or yetze</em> -- 'and my judgments shine forth like the light.' <em>Mishpat</em> (justice/judgment) made visible and clear through the prophetic proclamation. The prophets' devastating words are the light that exposes what the morning clouds of ephemeral repentance conceal.</p>",
        "6": "<p><strong>Ki chesed chafatzti ve-lo zavach</strong> -- 'For I desire covenant loyalty and not sacrifice.' The most programmatic verse in Hosea -- quoted twice by Jesus (Matt 9:13; 12:7). <em>Chafatz</em> (H2654, to delight in/desire) -- YHWH's desire is not for ritual performance but for covenant relationship expressed in loyalty. <em>Chesed</em> (H2617, covenant love/loyalty/steadfast love) -- the term that Hosea has used throughout (2:19; 4:1) as the missing virtue. <em>Ve-lo zavach</em> (not sacrifice) -- this is not an absolute rejection of the sacrificial system but a statement of priority: when chesed is absent, sacrifice is unacceptable. <em>Ve-daath Elohim mi-olot</em> -- 'the knowledge of God rather than burnt offerings.' <em>Daath Elohim</em> is the relational knowledge of the covenant that Hosea has established as the central virtue (4:1, 6). Jesus applies this verse twice: to defend his association with sinners (Matt 9:13 -- mercy is the priority) and to defend his disciples' grain-plucking on the Sabbath (Matt 12:7 -- covenant love ranks above ritual regulation). The verse becomes a hermeneutical key for how the new covenant reads the old.</p>",
        "7": "<p><strong>Ve-hemah ke-Adam avru verit</strong> -- 'But like Adam they have transgressed the covenant.' <em>Adam</em> can be read as 'humanity' in general or as a specific place name; the MKT reads it as 'Adam' (the first human) and thus as a typological comparison: Israel has repeated Adam's covenant transgression. The covenant at Sinai mirrors the covenant at Eden: both involved prohibition, both were violated by human choice, both resulted in expulsion from the divine presence. <em>Sham bagdu vi</em> -- 'there they have dealt faithlessly with me.' The faithlessness is geographically specific -- at the covenant sites (Adam, Gilead) where covenant was made and violated.</p>",
        "8": "<p><strong>Gilad qiryat poalei aven</strong> -- 'Gilead is a city of evildoers.' Gilead was a Transjordanian region associated with violence and political instability. <em>Aquvah mi-dam</em> -- 'stained with blood.' The city stained with blood (perhaps the murders of 2 Kgs 15:25-30 in the territory) is the concrete instantiation of the social breakdown described in 4:2. The idolatry of the cult (chs 4-5) and the violence of the social order are twin symptoms of the same covenant failure.</p>",
        "9": "<p><strong>U-khe-chavei ish gedudim chakeh kohen</strong> -- 'As raiders lie in wait for someone, so do bands of priests.' The priests have become organized criminals -- not merely corrupt but actively predatory. <em>Derekh yirtzachu shekhemah</em> -- 'they murder on the road to Shechem.' Shechem was a cultic city and the site of covenant assemblies (Josh 24). The road to the covenant assembly site has become the road of priestly ambush. <em>Ki zimah asu</em> -- 'they commit outrages.' <em>Zimah</em> (H2154, outrage/crime/lewdness) -- the strongest vocabulary for moral atrocity. The priestly institution has become a criminal enterprise.</p>",
        "10": "<p><strong>Be-veit Yisrael raiti shaeruriyah</strong> -- 'I have seen a horrible thing in the house of Israel.' <em>Shaeruriyah</em> (H8186, horrible thing/atrocity) -- a word reserved for the most extreme covenant violations (cf. Jer 5:30; 23:14). <em>Sham zenut le-Efrayim</em> -- 'Ephraim's prostitution is there.' The spiritual fornication has become so normalized that it is simply 'there' -- part of the landscape of the northern kingdom's religious life. <em>Nitma Yisrael</em> -- 'Israel is defiled.' The defilement (<em>tame</em>) is complete: the covenant people has become ritually impure from within through its own idolatry.</p>",
        "11": "<p><strong>Gam-Yehudah shat qatzir lakh</strong> -- 'Also, O Judah, a harvest is appointed for you.' The harvest (<em>qatzir</em>, H7105) can be positive (restoration, as in Hos 2:22-23) or negative (judgment, as in Joel 3:13; Rev 14:15). Here the ambiguity is intentional: Judah's harvest-appointment comes when YHWH restores (<em>be-shuvi shevut ammi</em>) the fortunes of his people. The verse bridges the judgment of ch 5-6 and the restoration that the book promises: Judah's 'harvest' is tied to the broader divine restoration of the covenant people. The chapter ends on the threshold between judgment and hope -- the characteristic Hosea position.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', 'hosea')
    merge_comm(existing, HOSEA)
    save_comm('mkt-original', 'hosea', existing)
    print('Hosea 1-6 mkt-original written.')

if __name__ == '__main__':
    main()
